CLUSTER:
[
 {
  "riskId": "risk.boundary-substitution.colo-follows-hyperscale-spec",
  "title": "Wholesale colocation inherits hyperscale rack-power specs — the 'safe' 18% slice buys what its tenants tell it to",
  "narrative": "The model treats colocation (seg.colocation, 0.18) as an independent PDU-buying segment — the sticky, PDU-friendly counterweight to hyperscale substitution risk. But CBRE reports that European colo take-up is being driven by hyperscalers and AI/HPC providers leasing wholesale capacity, and in wholesale deals the tenant specifies the rack-power architecture, not the landlord. If hyperscale tenants standardize on busway + power-shelf fit-outs in their leased suites, the substitution the boundary excluded walks through the colocation door: the colo slice's PDU content per MW falls in lockstep with hyperscale's, while the segment share in the model sits untouched — and seg.colocation carries no sensitivity band at all to absorb it.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "CBRE reports European colocation take-up outstripping new supply, driven specifically by hyperscalers and AI/HPC providers — i.e., the marginal colo MW is a hyperscale-tenant MW, leased wholesale with tenant-specified fit-out",
    "refs": [
     "digest:seg-mix#c24",
     "digest:seg-mix#c15"
    ]
   },
   {
    "step": "propagation",
    "text": "Hyperscale tenants port their own rack-power standards (busway feeds, OCP-style in-rack shelves) into leased suites; colo landlords fit out to tenant spec, so the substitution path excluded at the boundary propagates into the colocation segment via the lease contract, not the landlord's preference",
    "refs": [
     "digest:seg-mix#c14",
     "ledger:seg.colocation"
    ]
   },
   {
    "step": "model-impact",
    "text": "seg.colocation's 0.18 rests on a single Synergy global capacity series (20–22% across vintages) with no sensitivityRange; the model has zero mechanism to register falling PDU content per colo MW, so the colocation slice is overstated in absolute PDU-euro terms during exactly the venture's entry window",
    "refs": [
     "ledger:seg.colocation",
     "digest:seg-mix#c1",
     "digest:seg-mix#c7"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Rack-power architecture named in wholesale colo fit-out specs and tenant technical requirements",
    "where": "TED (EU tenders electronic daily) and TenderNed for NL/DE data-center fit-out packages; Equinix and Digital Realty capex/earnings calls (xScale / hyperscale JV commentary)",
    "threshold": "≥2 CE wholesale deals where tenant spec mandates busway or shelf-based distribution in leased suites",
    "updates": "increases"
   },
   {
    "signal": "Colo landlords marketing 'OCP-ready' or shelf-compatible white space in CE",
    "where": "Dutch Data Center Association annual report; Frankfurt operator (e.g., NTT, CyrusOne, Vantage) product announcements and OCP Regional Summit EMEA talks",
    "threshold": "First CE colo operator advertising OCP-ready suites as standard product",
    "updates": "increases"
   },
   {
    "signal": "Retail vs wholesale mix in CE colo absorption",
    "where": "CBRE European Data Centres quarterly reports",
    "threshold": "Wholesale/hyperscale-leased share of CE take-up exceeding ~60%",
    "updates": "increases"
   }
  ],
  "judgeTotal": 18,
  "distinctByJudge": "The risk inverts the model's own hedge logic — colocation is the 'safe' counterweight, but the whyMissable field shows wholesale lease structure hands rack-power spec to the very hyperscale tenants the hedge excludes. Docked one point because a founder tracking hyperscale substitution might eventually ask who specifies wholesale fit-outs, though the surface framing does actively hide it."
 },
 {
  "riskId": "risk.structure-independence.ce-hyperscale-global-split-mirage",
  "title": "CE hyperscale 0.44 is a global-split mirage: Europe's self-build sits in Ireland/Sweden/Belgium, and Frankfurt is colocation",
  "narrative": "The segment axis applies Synergy's GLOBAL capacity split (48% hyperscale × 0.91) to a geography axis built entirely on Central European colocation MW. But CBRE's Europe-specific data says ~60% of operational hyperscaler self-build capacity sits in Ireland, the Netherlands, Sweden and Belgium — three of the four outside CE-7 — and that European colocation 'will remain significantly larger' than hyperscale self-build. Inside CE, hyperscalers show up mostly as TENANTS in Frankfurt and Amsterdam colo halls, where the fit-out and PDU procurement decision often sits with the colo operator or a global tenant framework, not a CE buyer. The model's biggest cell — DE × hyperscale — is therefore substantially phantom, and the true CE mix is inverted toward colocation buyers with different procurement paths.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "CBRE Q4-2025: ~60% of Europe's operational hyperscaler self-build capacity is located in Ireland, Netherlands, Sweden, Belgium; and colocation in Europe 'will remain significantly larger' than hyperscaler self-build — the opposite ordering from the model's 0.44 vs 0.18",
    "refs": [
     "digest:seg-mix#c16",
     "digest:seg-mix#c15"
    ]
   },
   {
    "step": "propagation",
    "text": "The 0.44 was produced by rescaling a raw GLOBAL Synergy share; no Europe- or CE-scoped hyperscale share has ever been observed, and the 'cross-check' (Q1-2025 44% global) is a different quantity that coincidentally matches. Hyperscale demand in CE flows through colo halls whose take-up already outstrips supply",
    "refs": [
     "ledger:seg.hyperscale",
     "digest:seg-mix#c6",
     "digest:seg-mix#c24"
    ]
   },
   {
    "step": "model-impact",
    "text": "The DE(0.50) × hyperscale(0.44) cell — the largest cell in the cube and the implied beachhead for selling to large operators — is largely phantom in CE; weight belongs in colocation, whose buyer, spec and procurement cadence differ from what the venture is building for",
    "refs": [
     "ledger:geo.DE",
     "ledger:seg.colocation",
     "profile:Who is the primary buyer you'll sell through first?"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Europe hyperscale self-build vs colocation GW split, updated quarterly",
    "where": "CBRE 'Europe Data Centres' quarterly figures report; DCD coverage of CBRE releases",
    "threshold": "CE-7 hyperscale self-build share reported <30% of CE capacity",
    "updates": "increases"
   },
   {
    "signal": "Country-level ownership mix (colocation/hyperscale/enterprise) for DE and NL",
    "where": "EUDCA 'State of European Data Centres' annual report country tables",
    "threshold": "Germany capacity shown as majority colocation-operated",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17,
  "distinctByJudge": "The scope-mismatch insight — that 'triangulated' Synergy vintages agree only among GLOBAL figures never observed at European scope — is exactly the kind of thing the maturity label hides, per whyMissable. Docked one point because the likelihood rationale admits a 'cross-corpus tension' already flags that no CE-scoped share exists, so a careful ledger reader had a breadcrumb."
 }
]

